import{_ as t,o,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Facebook Aggregate Reporting Changes","description":"","frontmatter":{"title":"Facebook Aggregate Reporting Changes","slug":"facebook-aggregate-reporting-changes"},"headers":[],"relativePath":"marketer-hub/facebook-aggregate-reporting-changes.md","filePath":"marketer-hub/facebook-aggregate-reporting-changes.md"}'),i={name:"marketer-hub/facebook-aggregate-reporting-changes.md"};function n(s,e,c,l,d,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Being a certified mobile measurement partner (MMP) with Meta (Facebook), Branch guarantees full alignment with certain reporting practices to help balance the privacy of Meta&#39;s users with the needs of marketers to get useful insights into their campaigns.</p><p>Starting on <strong>May 8th, 2023</strong>, Branch may redact specific metrics/events (ex. INSTALLS) through the Branch Dashboard or through Aggregate Exports of Facebook-attributed campaigns when aggregation levels are not high enough to prevent the potential de-anonymization of specific Facebook users. In a large majority of situations, this is only likely to happen in the very earliest portion of the campaign cycle where traffic is at its lowest. Data is not lost and will be shown once required aggregation levels are met.</p><p>When the number of users/impressions included in the metric does not meet/exceed the necessary threshold, Branch will display &quot;<strong>undisclosed</strong>&quot; in Dashboard Reports and <code>null</code> in Aggregate Exports. This is similar to how Branch cannot show non-aggregated view-through and click-through data from Facebook on the Branch Dashboard.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Between April 24 and May 8, 2023, Branch temporarily applied more stringent thresholds for Facebook/Meta reporting. We have since worked closely with Meta regarding a solution that complies with Meta’s policies and restores industry-standard functionality.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Exceptions</p><p>When the conversion is attributed to <strong>Facebook</strong> via <a href="./facebook-install-referrer.html">Facebook Install Referrer</a> or there is no Facebook Campaign ID, it is exempt from these requirements; thus, data will show in the Dashboard and in Exports.</p></div><h2 id="what-does-it-look-like" tabindex="-1">What does it look like? <a class="header-anchor" href="#what-does-it-look-like" aria-label="Permalink to &quot;What does it look like?&quot;">​</a></h2><h3 id="dashboard-reports" tabindex="-1">Dashboard Reports <a class="header-anchor" href="#dashboard-reports" aria-label="Permalink to &quot;Dashboard Reports&quot;">​</a></h3><p>The first place you will notice a change is within the Branch Dashboard when looking at Facebook-related <a href="./paid-ads-analytics.html">Ads Analytics</a>. More specifically when you are comparing Facebook data in the Events table.</p><p>In the example screenshot above, you will notice that when data reported for Facebook does not exceed the right threshold, &quot;undisclosed&quot; will replace the real value while abstracting the data from the <code>TOTAL</code> values.</p><h3 id="aggregate-exports" tabindex="-1">Aggregate Exports <a class="header-anchor" href="#aggregate-exports" aria-label="Permalink to &quot;Aggregate Exports&quot;">​</a></h3><p>The second place you will notice a change is in Branch&#39;s Aggregate Data Exports. When exporting aggregate Facebook data, you will see changes in the following export fields:</p><table tabindex="0"><thead><tr><th>API</th><th>Data Sources</th><th>Aggregation/Measures</th></tr></thead><tbody><tr><td><a href="./aggregate-api.html">Aggregate</a></td><td>- <code>cost</code> - <code>eo_click</code> - <code>eo_impression</code> - <code>eo_install</code> - <code>eo_open</code> - <code>eo_reinstall</code> - <code>SKAdNetwork-valid-messages</code></td><td>- <code>unique_count</code> - <code>total_count</code> - <code>cost</code> - <code>cost_in_local_currency</code></td></tr><tr><td><a href="./query-api.html">Query</a></td><td>- <code>cost</code> - <code>eo_click</code> - <code>eo_impression</code> - <code>eo_install</code> - <code>eo_open</code> - <code>eo_reinstall</code> - <code>xx_click</code> - <code>xx_impression</code></td><td>- <code>unique_count</code> - <code>total_count</code> - <code>cost</code> - <code>cost_in_local_currency</code></td></tr><tr><td><a href="./cohort-api.html">Cohort</a></td><td>- <code>install_cohort</code> - <code>reengagement_cohort</code></td><td>- All Measures</td></tr></tbody></table><h4 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h4><p>When running any of the above Aggregate Data Exports where the Facebook-attributed metric/event does not meet the threshold, the API response for the Aggregation/Measure will return <code>null</code>. Otherwise, it will return the real/expected value.</p><h2 id="reporting-best-practices" tabindex="-1">Reporting Best Practices <a class="header-anchor" href="#reporting-best-practices" aria-label="Permalink to &quot;Reporting Best Practices&quot;">​</a></h2><p>If you are finding that your reports are showing &quot;undisclosed&quot; in Dashboard Reports or <code>null</code> in Aggregate Exports, follow these steps to help:</p><ol><li>Wait for additional campaign traffic - If you have just begun running a new campaign, it can take a short time to generate sufficient traffic volumes to meet the thresholds. You may opt to increase spend during this initial period to reach it more quickly.</li><li>Select reporting dimensions higher than Campaign-level, such as Ad Partner Level, to see overall Facebook performance.</li><li>Reach out to your Ads Account Manager - Talk to your Meta team or agency about how you can set up campaigns so you regularly exceed privacy thresholds.</li></ol>',18)])])}const u=t(i,[["render",n]]);export{p as __pageData,u as default};
